import{_ as r,c as t,o as p,a as b}from"./app.015fbf38.js";const m='{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E00\u7AE0","description":"","frontmatter":{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E00\u7AE0","date":"2018-05-17T06:00:43.000Z","categories":["\u8B80\u7D93\u7D00\u9304"]},"headers":[],"relativePath":"Bike/BikeTravel/20180517_\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E00\u7AE0.md","lastUpdated":1648513476165}',_={},e=b('<p><img src="https://farm1.staticflickr.com/959/41373346144_21b4588804.jpg" alt=""></p><p>\u5728\u63A2\u8A0E\u672C\u7AE0\u5167\u5BB9\u4E4B\u524D\uFF0C\u53EF\u4EE5\u4E86\u89E3\u4E00\u4E0B\u4F46\u4EE5\u7406\u6240\u8655\u7684\u6642\u4EE3\u80CC\u666F<br> \u4F46\u4EE5\u7406\u51FA\u751F\u7684\u5E74\u4EE3\u5927\u7D04\u662F\u5357\u570B\u7336\u5927-\u7D04\u897F\u4E9E\u738B\u7684\u4E16\u4EE3<br> \u7D04\u897F\u4E9E\u738B\u5BE6\u65BD\u5B97\u6559\u6539\u9769\uFF0C\u884C\u795E\u773C\u4E2D\u770B\u70BA\u6B63\u7684\u4E8B\uFF0C\u6548\u6CD5\u5927\u885B\u6240\u884C\u7684<br> \u62C6\u6BC0\u5076\u50CF\uFF0C\u4F7F\u4EE5\u8272\u5217\u4EBA\u5B88\u5F8B\u6CD5\u3001\u903E\u8D8A\u7BC0\uFF0C\u958B\u555F\u4E86\u9748\u6027\u5FA9\u8208<br></p><p>\u7336\u5927\u672B\u5F8C\u56DB\u500B\u738B\u7D04\u54C8\u65AF\u3001\u7D04\u96C5\u656C\u3001\u7D04\u96C5\u65A4\u3001\u897F\u5E95\u5BB6<br> \u9664\u4E86\u7D04\u96C5\u65A4\u662F\u7D04\u897F\u4E9E\u7684\u5B6B\u5B50\u5916\uFF0C\u5176\u4ED6\u4E09\u500B\u90FD\u662F\u7D04\u897F\u4E9E\u7684\u5152\u5B50<br> \u53EF\u60DC\u6700\u5F8C\u90FD\u504F\u96E2\u795E\u7684\u9053\uFF0C\u884C\u8036\u548C\u83EF\u773C\u4E2D\u770B\u70BA\u60E1\u7684\u4E8B</p><p>\u7D04\u54C8\u65AF\u662F\u627F\u7E7C\u7D04\u897F\u4E9E\uFF0C\u4F46\u4F5C\u738B\u4E09\u500B\u6708\uFF0C\u5C31\u88AB\u6CD5\u8001\u5C3C\u54E5\u5EE2\u6389<br> \u6CD5\u8001\u5C3C\u54E5\u5C07\u4ED6\u9396\u7981\uFF0C\u4E26\u5411\u7336\u5927\u570B\u52D2\u64C4\u91D1\u9280\uFF0C\u6700\u5F8C\u6B7B\u5728\u57C3\u53CA</p><p>\u6CD5\u8001\u5C3C\u54E5\u53E6\u7ACB\u4EE5\u5229\u96C5\u656C\u4F5C\u7336\u5927\u7684\u738B\uFF0C\u53C8\u7D66\u4ED6\u6539\u540D\u53EB\u7D04\u96C5\u656C<br> \u6B64\u6642\u57C3\u53CA\u7684\u52E2\u529B\u9010\u6F38\u64F4\u5F35\uFF0C\u800C\u5DF4\u6BD4\u502B\u4E5F\u6B63\u5728\u5D1B\u8D77\u4E2D<br> \u5357\u570B\u7336\u5927\u53EA\u80FD\u5728\u5217\u5F37\u7576\u4E2D\uFF0C\u593E\u7E2B\u4E2D\u6C42\u751F\u5B58<br> \u7D04\u96C5\u656C\u70BA\u4E86\u8A0E\u597D\u57C3\u53CA\uFF0C\u5148\u5411\u6CD5\u8001\u5C3C\u54E5\u9032\u8CA2\u91D1\u9280<br> \u4E4B\u5F8C\u53C8\u8F49\u5411\u5DF4\u6BD4\u502B\uFF0C\u5C0B\u6C42\u6C42\u52A9\uFF0C\u670D\u4E8B\u5DF4\u6BD4\u502B\u4E09\u5E74<br> \u7136\u5F8C\u80CC\u53DB\u5DF4\u6BD4\u502B\uFF0C\u7D50\u679C\u62DB\u4F86\u4E86\u5927\u8ECD\u58D3\u5883<br> \u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u7528\u9285\u934A\u9396\u4F4F\u4ED6\uFF0C\u628A\u4ED6\u5E36\u5230\u5DF4\u6BD4\u502B\u53BB<br> \u9019\u6642\u6709\u4E00\u6279\u4EBA\u88AB\u64C4\u53BB\uFF0C\u4F46\u4EE5\u7406\u53EF\u80FD\u662F\u7576\u4E2D\u88AB\u64C4\u7684\u4E00\u54E1</p><p>\u5F9E\u7B2C\u4E00\u7AE0\u63CF\u7E6A\u4F46\u4EE5\u7406\u7684\u8F2A\u5ED3\u5982\u4E0B\uFF1A</p><ol><li><p>\u4F46\u4EE5\u7406\u7684\u5E74\u7D00\u8207\u5BB6\u4E16\u80CC\u666F<br> \u63A8\u6E2C\u4F46\u4EE5\u7406\u6B64\u523B\u7684\u5E74\u7D00\u61C9\u8A72\u70BA\u9752\u5C11\u5E74\u6642\u671F(15~20)\u4E4B\u9593<br> \u800C\u5BB6\u65CF\u80CC\u666F\u61C9\u8A72\u70BA\u5730\u65B9\u671B\u65CF(\u88AB\u64C4\u7684\u90FD\u662F\u8CB4\u5191)<br> \u88AB\u6311\u9078\u9032\u7687\u5BAE\u7684\u540C\u6642\u4E5F\u5177\u5099\u8070\u660E\u624D\u667A</p></li><li><p>\u4F46\u4EE5\u7406\u7684\u4EBA\u683C\u7279\u8CEA<br> \u5F9E\u4F46\u4EE5\u7406\u8207\u7E3D\u7BA1\u7684\u5C0D\u8A71\u53EF\u770B\u51FA\uFF0C\u4ED6\u5BCC\u6709\u540C\u7406\u5FC3<br> \u4E0D\u70BA\u96E3\u5C0D\u65B9\u7ACB\u5834\u70BA\u524D\u63D0\u4E0B\uFF0C\u5E0C\u671B\u4E5F\u80FD\u9054\u5230\u81EA\u5DF1\u7684\u671F\u671B<br> \u4ED6\u6240\u8AC7\u7684\u689D\u4EF6\uFF0C\u4E00\u958B\u59CB\u5148\u8A66\u9A57\u5341\u5929\uFF0C\u767C\u73FE\u8EAB\u9AD4\u72C0\u6CC1\u53CD\u800C\u66F4\u597D<br> \u9032\u800C\u5168\u9762\u4E0D\u98F2\u7528\u738B\u81B3\uFF0C\u4E5F\u56E0\u70BA\u5C0D\u795E\u7684\u656C\u91CD\u3001\u8654\u8AA0\u7684\u5FC3\u5FD7<br> \u53CD\u800C\u52DD\u904E\u5176\u4ED6\u7684\u8853\u58EB\uFF0C\u4E5F\u5177\u5099\u4E86\u89E3\u7570\u5922\u7684\u6069\u8CDC</p></li><li><p>\u4F46\u4EE5\u7406\u5177\u5099\u9818\u8896\u9B45\u529B<br> \u5728\u7B2C\u4E00\u7AE0\u4E2D\uFF0C\u770B\u898B\u8207\u7687\u5BAE\u7684\u7E3D\u7BA1\u5C0D\u8AC7\u3001\u8AC7\u689D\u4EF6<br> \u5F9E\u982D\u5230\u672B\u4E86\u90FD\u662F\u4F46\u4EE5\u7406\u5728\u6E9D\u901A\u4EA4\u6D89\uFF0C\u5176\u4ED6\u670B\u53CB\u53EA\u5728\u4E00\u65C1<br> \u5728\u9019\u6A23\u7684\u8655\u5883\u4E0B\uFF0C\u5176\u5BE6\u53EF\u770B\u5230\u4F46\u4EE5\u7406\u9858\u610F\u627F\u64D4\u98A8\u96AA\u3001\u8CAC\u4EFB<br> \u4ED6\u4E0D\u6015\u7E3D\u7BA1\u70BA\u96E3\u4ED6\uFF0C\u6216\u662F\u4E00\u8209\u544A\u5230\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u9762\u524D</p></li></ol><p>\u5F9E\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u7684\u610F\u5716\uFF0C\u770B\u51FA\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u60F3\u7D71\u6CBB\u4E16\u754C\u7684\u91CE\u5FC3</p><ol><li><p>\u64C4\u63A0\u6B96\u6C11\u5730\u7684\u540D\u5BB6\u5B50\u5F1F\u3001\u512A\u79C0\u4EBA\u624D<br> \u9019\u908A\u63D0\u5230\u9664\u4E86\u4F46\u4EE5\u7406\u4EE5\u5916\u9084\u6709\u4E09\u500B\u670B\u53CB\uFF0C\u90FD\u662F\u7336\u592A\u8CB4/\u671B\u65CF<br> \u738B\u9664\u4E86\u60F3\u8B93\u9019\u4E9B\u4E0A\u6D41\u4EBA\u58EB\u7576\u8853\u58EB\u5916\uFF0C\u4E5F\u60F3\u4F7F\u7528\u4ED6\u5011\u4F86\u7BA1\u7406\u7336\u5927\u4EBA</p></li><li><p>\u5B78\u7FD2\u5DF4\u6BD4\u502B\u6587\u5316\u3001\u6587\u5B57\uFF0C\u53D6\u5DF4\u6BD4\u502B\u540D\u5B57\uFF0C\u5168\u9762\u5DF4\u6BD4\u502B\u5316<br> \u900F\u904E\u6559\u5C0E\u6587\u5B57\u3001\u6587\u5316\u3001\u7FD2\u4FD7\uFF0C\u8B93\u9019\u4E9B\u88AB\u64C4\u7684\u7336\u5927\u570B\u4EBA\u6210\u70BA\u5DF4\u6BD4\u502B\u4EBA<br> \u800C\u5728\u5BAE\u4E2D\u7684\u9019\u56DB\u4F4D\u7336\u5927\u4EBA\uFF0C\u4E5F\u88AB\u738B\u547D\u4E0A\u5DF4\u6BD4\u502B\u540D\u5B57<br> \u800C\u540D\u5B57\u8207\u5DF4\u6BD4\u502B\u7684\u795E\u7957\u76F8\u95DC\uFF0C\u53EF\u77E5\u7576\u5730\u53D7\u7570\u6559\u6587\u5316\u5F71\u97FF\u751A\u9245<br> \u6211\u89BA\u5F97\u9019\u8DDF\u53F0\u7063\u88AB\u65E5\u672C\u7D71\u6CBB\u5F88\u985E\u4F3C\uFF0C\u53D6\u65E5\u672C\u540D\u5B57\u3001\u8B1B\u65E5\u6587\u3001\u53D7\u65E5\u5F0F\u6559\u80B2</p></li><li><p>\u900F\u904E\u5206\u767C\u738B\u81B3\uFF0C\u4F86\u62C9\u650F\u88AB\u64C4\u4E4B\u4EBA\u7684\u5FC3<br> \u4F46\u4EE5\u7406\u4E0D\u5403\u738B\u8CDC\u7684\u98DF\u7269\uFF0C\u5F88\u6709\u53EF\u80FD\u9019\u8207\u7576\u5730\u7684\u6587\u5316\u7FD2\u4FD7\u6709\u95DC<br> \u4E5F\u6709\u53EF\u80FD\u9019\u4E9B\u98DF\u7269\u88E1\u9762\uFF0C\u6DB5\u84CB\u4E86\u795E\u6240\u660E\u793A\u4E0D\u6F54\u6DE8\u7684\u52D5\u7269<br> \u6216\u662F\u98DF\u7269\u7684\u8655\u7406\u65B9\u5F0F\u4E0D\u7B26\u5408\u898F\u5B9A\uFF0C\u624D\u8B93\u4F46\u4EE5\u7406\u7ACB\u5B9A\u5FC3\u5FD7\u4E0D\u5403</p></li></ol><p>\u5982\u679C\u6C92\u6709\u4ED4\u7D30\u53BB\u7814\u7A76\u4F46\u4EE5\u7406\uFF0C\u53EF\u80FD\u6703\u4EE5\u70BA\u4ED6\u662F\u982D\u75DB\u4EBA\u7269<br> \u4E0D\u5403\u738B\u81B3\u3001\u5F8C\u9762\u4E5F\u6703\u770B\u5230\u4ED6\u4E0D\u5B88\u738B\u4E0B\u7684\u7981\u4EE4\u88AB\u9677\u5BB3<br> \u4F46\u5BE6\u969B\u67E5\u770B\uFF0C\u6703\u767C\u73FE\u4ED6\u5176\u5BE6\u662F\u5F88\u70BA\u5C0D\u65B9\u8655\u5883\u8457\u60F3\u7684\u4EBA</p><p><img src="https://farm1.staticflickr.com/885/41485890431_0ff80e622a.jpg" alt=""><br> \u6BD4\u8F03\u8B93\u6211\u6478\u4E0D\u8457\u982D\u7DD2\u7684\u662F\uFF0C\u70BA\u5565\u5DF4\u6BD4\u502B\u738B\u8981\u990A\u4E00\u7FA4\u8853\u58EB<br> \u7A76\u7ADF\u4E9B\u8853\u58EB\u80FD\u70BA\u570B\u5BB6\u5E36\u4F86\u751A\u9EBC\u5229\u76CA\u6216\u5E6B\u52A9!?<br> \u96E3\u9053\u8853\u58EB\u5C0D\u570B\u5BB6\u5177\u6709\u91CD\u8981\u7684\u5F71\u97FF\u529B!?</p>',11),a=[e];function i(l,o,c,s,n,d){return p(),t("div",null,a)}var T=r(_,[["render",i]]);export{m as __pageData,T as default};
